package be.schaubroeck.lpb.rkm.rekenmotor.cache;

import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext.Scope;
import be.schaubroeck.lpb.tools.RegimeRszppo;
import be.schaubroeck.lpb.tools.criteria.CriteriaBuilder;
import be.schaubroeck.lpb.tools.jpa.gl.RegimeRszppoPk;
import be.schaubroeck.lpb.tools.service.RegimeRszppoService;
import be.schaubroeck.lpb.tools.util.TimeLogContext;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import org.apache.commons.lang.builder.EqualsBuilder;
import org.apache.commons.lang.builder.HashCodeBuilder;
import org.joda.time.LocalDate;

import java.util.HashMap;
import java.util.List;
import java.util.Map;

public abstract class AbstractCachedRegimeRszppoService implements CachedService, RegimeRszppoService {

    protected abstract RegimeRszppoService getWrappedService();

    protected static class CachedRegimeRszppoBuffer {

        private final Map<RegimeRszppoKey, List<RegimeRszppo>> regimeRszppoBuffer = new HashMap<>();

        public List<RegimeRszppo> get(RegimeRszppoKey key) {
            return regimeRszppoBuffer.get(key);
        }

        public void put(RegimeRszppoKey key, List<RegimeRszppo> lijst) {
            regimeRszppoBuffer.put(key, lijst);
        }

        public boolean containsKey(RegimeRszppoKey key) {
            return regimeRszppoBuffer.containsKey(key);
        }

        public void clear() {
            regimeRszppoBuffer.clear();
        }
    }

    protected abstract CachedRegimeRszppoBuffer getBuffer();

    public AbstractCachedRegimeRszppoService() {
        super();
        CacheContext.getInstance().registerCachedServices(this, Scope.ADMIN);
    }

    @Override
    public RegimeRszppo getByCategorieLoonCodeEnDatum(Integer categorie, Integer loonCode, LocalDate datum) {
        TimeLogContext.getInstance().startTimeLogging("AbstractCachedRegimeRszppoService.getByCategorieLoonCodeEnDatum");
        CachedRegimeRszppoBuffer buffer = getBuffer();
        List<RegimeRszppo> results;
        RegimeRszppoKey key = new RegimeRszppoKey(categorie, loonCode);
        if (buffer.containsKey(key)) {
            results = buffer.get(key);
        } else {
            results = getWrappedService().findByCategorieLoonCode(categorie, loonCode);
            buffer.put(key, results);
        }
        RegimeRszppo result = findRegimeByDate(results, datum);
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }

    private RegimeRszppo findRegimeByDate(List<RegimeRszppo> lijst, LocalDate datum) {
        RegimeRszppo result = null;
        for (RegimeRszppo regime : lijst) {
            LocalDateInterval regimeInterval = new LocalDateInterval(regime.getBeginDatum(), regime.getEindDatum());
            if (regimeInterval.contains(datum)) {
                result = regime;
                break;
            }
        }
        return result;
    }

    @Override
    public void clearCache() {
        getBuffer().clear();
    }

    private static class RegimeRszppoKey {

        private final int categorie;
        private final int loonCode;

        public RegimeRszppoKey(int categorie, int loonCode) {
            this.categorie = categorie;
            this.loonCode = loonCode;
        }

        @Override
        public boolean equals(final Object object) {
            if (!(object instanceof RegimeRszppoKey)) {
                return false;
            }
            RegimeRszppoKey rhs = (RegimeRszppoKey) object;
            return new EqualsBuilder().append(this.categorie, rhs.categorie).append(this.loonCode, rhs.loonCode).isEquals();
        }

        private static final int HASH_CST1 = 937;
        private static final int HASH_CST2 = 787;

        @Override
        public int hashCode() {
            return new HashCodeBuilder(HASH_CST1, HASH_CST2).append(categorie).append(loonCode).toHashCode();
        }
    }

    //Forwarding naar Standard...Service, we gebruiken hier geen overerving omdat we de @Transcational willen vermijden.

    @Override
    public List<RegimeRszppo> findByCategorieLoonCode(Integer categorie, Integer loonCode) {
        return getWrappedService().findByCategorieLoonCode(categorie, loonCode);
    }

    @Override
    public RegimeRszppo create(RegimeRszppo regimeRszppo) {
        return getWrappedService().create(regimeRszppo);
    }

    @Override
    public RegimeRszppo update(RegimeRszppo regimeRszppo) {
        return getWrappedService().update(regimeRszppo);
    }

    @Override
    public void delete(RegimeRszppo regimeRszppo) {
        getWrappedService().delete(regimeRszppo);
    }

    @Override
    public RegimeRszppo getById(RegimeRszppoPk id) {
        return getWrappedService().getById(id);
    }

    @Override
    public RegimeRszppo getById(RegimeRszppoPk id, String fetchFields) {
        return getWrappedService().getById(id, fetchFields);
    }

    @Override
    public RegimeRszppo getByCriteria(CriteriaBuilder cb) {
        return getWrappedService().getByCriteria(cb);
    }

    @Override
    public List<RegimeRszppo> findAll() {
        return getWrappedService().findAll();
    }

    @Override
    public List<RegimeRszppo> findAll(String fetchFields) {
        return getWrappedService().findAll(fetchFields);
    }

    @Override
    public List<RegimeRszppo> findByCriteria(CriteriaBuilder cb) {
        return getWrappedService().findByCriteria(cb);
    }

    @Override
    public Integer countByCriteria(CriteriaBuilder cb) {
        return getWrappedService().countByCriteria(cb);
    }
}
